/// This is the TTL deadline: initial_block + (frequency * index) + ttl
pub fn expiry_block(&self) -> u64 {
    self.initial_block.saturating_add(self.frequency.saturating_mul(self.index)).saturating_add(self.ttl)
}

pub fn ttl_deadline(&self, execution_index: u64) -> u64 { self.expected_block(execution_index).saturating_add(self.ttl as u64) }
